  final String k;    // kanji
  final String en;   // english meaning
  final String on;   // onyomi
  final String kun;  // kunyomi
  final String ja;   // japanese reading (hiragana) e.g. 'ひ・にち'
  final String rom;  // romaji  e.g. 'hi / nichi'
  final int jlpt;
  final int freq;
  final int? frame;  // Heisig frame
  final String kw;   // mnemonic keyword
  final String cat;  // category
  final String ex1w; // example word 1
  final String ex1r; // reading 1
  final String ex1e; // english 1
  final String ex2w;
  final String ex2r;
  final String ex2e;
  const KanjiEntry(this.k,this.en,this.on,this.kun,this.ja,this.rom,
      this.jlpt,this.freq,this.frame,this.kw,this.cat,
      this.ex1w,this.ex1r,this.ex1e,this.ex2w,this.ex2r,this.ex2e);
}

